        }

        .main-title::after {
            color: var(--neon-cyan);
            animation: glitch-2 3s infinite linear alternate-reverse;
            clip-path: polygon(0 65%, 100% 65%, 100% 100%, 0 100%);
        }

        @keyframes glitch {
            0%, 90%, 100% { transform: translate(0); }
            92% { transform: translate(-5px, 2px); }
            94% { transform: translate(5px, -2px); }
            96% { transform: translate(-3px, 0); }
        }

        @keyframes glitch-1 {
            0%, 100% { transform: translate(0); }
            20% { transform: translate(-3px, 0); }
            40% { transform: translate(3px, 0); }
        }

        @keyframes glitch-2 {
            0%, 100% { transform: translate(0); }
            20% { transform: translate(3px, 0); }
            40% { transform: translate(-3px, 0); }
        }

        .eng-name {
            font-family: 'Share Tech Mono', monospace;
            font-size: 20px;
            color: var(--neon-green);
            letter-spacing: 4px;
            margin: 15px 0;
            text-shadow: 0 0 20px var(--neon-green);
            animation: pulse 2s infinite;
        }

        @keyframes pulse {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.5; }
        }

        .subtitle {
            font-size: 11px;
            color: rgba(255,102,0,0.9);
            max-width: 420px;
            margin: 6px auto 8px;
            padding: 4px 12px;
            border: none;
            background: transparent;
            position: relative;
            font-family: 'Share Tech Mono', monospace;
            letter-spacing: 0.5px;
            line-height: 1.4;
        }

        .subtitle::before, .subtitle::after {
            content: '//';
            position: absolute;
            color: rgba(255,102,0,0.5);
            font-size: 10px;
            top: 50%;
            transform: translateY(-50%);
        }

        .subtitle::before { left: 0; }
        .subtitle::after { right: 0; }

        /* 故障艺术效果 - 简化版 */
        .subtitle-glitch {
            position: relative;
            display: inline-block;
        }

        .subtitle-glitch::before,
        .subtitle-glitch::after {
            content: attr(data-text);
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            opacity: 0.6;
        }

        .subtitle-glitch::before {
            color: var(--neon-pink);
            animation: glitch-1 3s infinite linear alternate-reverse;
            clip-path: polygon(0 0, 100% 0, 100% 25%, 0 25%);
        }

        .subtitle-glitch::after {
            color: var(--neon-cyan);
            animation: glitch-2 4s infinite linear alternate-reverse;
            clip-path: polygon(0 75%, 100% 75%, 100% 100%, 0 100%);
        }

        /* 状态栏 */
        .status-bar {
            display: flex;
            justify-content: center;
            gap: 40px;
            padding: 20px;
            font-family: 'Share Tech Mono', monospace;
            font-size: 12px;
            color: var(--neon-cyan);
            border-top: 1px solid rgba(0,255,255,0.2);
            border-bottom: 1px solid rgba(0,255,255,0.2);
            margin-bottom: 40px;
        }

        .status-item {
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .status-dot {
            width: 8px;
            height: 8px;
            background: var(--neon-green);
            border-radius: 50%;
            animation: blink 1s infinite;
        }

        @keyframes blink {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.3; }
        }

        /* 游戏区域 */
        main {
            max-width: 1200px;
            margin: 0 auto;
            padding: 20px;
        }

        .section-title {
            font-size: 28px;
            margin-bottom: 30px;
            color: var(--neon-pink);
            text-transform: uppercase;
            letter-spacing: 4px;
            position: relative;
            display: inline-block;
        }

        .section-title::after {
            content: '';
            position: absolute;
            bottom: -5px;
            left: 0;
            width: 100%;
            height: 2px;
            background: linear-gradient(90deg, var(--neon-pink), transparent);
        }

        .games-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
            gap: 25px;
            margin-bottom: 60px;
        }

        .game-card {
            background: rgba(0,0,0,0.8);
            border: 1px solid rgba(255,0,255,0.3);
            padding: 25px;
            position: relative;
            transition: all 0.3s;
            overflow: hidden;
        }

        .game-card::before {
            content: '';
            position: absolute;
            top: 0;
            left: -100%;
            width: 100%;
            height: 2px;
            background: linear-gradient(90deg, transparent, var(--neon-cyan), transparent);
            transition: left 0.5s;
        }

        .game-card:hover::before { left: 100%; }

        .game-card:hover {
            border-color: var(--neon-cyan);
            box-shadow: 0 0 30px rgba(0,255,255,0.2);
            transform: translateY(-3px);
        }

        .game-id {
            position: absolute;
            top: 10px;
            right: 10px;
            font-family: 'Share Tech Mono', monospace;
            font-size: 10px;
            color: rgba(255,255,255,0.3);
        }

        .game-icon {
            font-size: 40px;
            margin-bottom: 15px;
            filter: drop-shadow(0 0 10px rgba(255,255,255,0.3));
        }

        .game-title { font-size: 20px; margin-bottom: 8px; color: #fff; }

        .game-meta {
            font-family: 'Share Tech Mono', monospace;
            font-size: 11px;
            color: var(--neon-green);
            margin-bottom: 12px;
        }

        .game-desc { font-size: 13px; color: #aaa; line-height: 1.6; margin-bottom: 15px; }

        .play-link {
            display: inline-block;
            background: transparent;
            border: 1px solid var(--neon-cyan);
            color: var(--neon-cyan);
            padding: 8px 20px;
            text-decoration: none;
            font-family: 'Share Tech Mono', monospace;
            font-size: 12px;
            letter-spacing: 2px;
            transition: all 0.3s;
            position: relative;
            overflow: hidden;
        }

        .play-link::before {
            content: '';
            position: absolute;
            top: 0;
            left: -100%;
            width: 100%;
            height: 100%;
            background: var(--neon-cyan);
            transition: left 0.3s;
            z-index: -1;
        }

        .play-link:hover::before { left: 0; }
        .play-link:hover { color: #000; }

        .play-link.disabled {
            border-color: #333;
            color: #555;
            pointer-events: none;
        }
        .play-link.disabled::before { display: none; }

        /* ASCII艺术 */
        .ascii-art {
            font-family: 'Share Tech Mono', monospace;
            font-size: 10px;
            line-height: 1.2;
            color: rgba(0,255,255,0.3);
            text-align: center;
            margin: 40px 0;
            white-space: pre;
        }

        /* 页脚 */
        footer {
            text-align: center;
            padding: 40px 20px;
            border-top: 1px solid rgba(255,0,255,0.2);
            font-family: 'Share Tech Mono', monospace;
            font-size: 11px;
            color: rgba(255,255,255,0.4);
        }

        footer .blink { animation: blink 2s infinite; }

        .visit-counter {
            text-align: center;
            padding: 10px;
            margin-top: 10px;
            font-size: 0.85rem;
            opacity: 0.8;
        }

        .visit-counter span {
            color: var(--neon-cyan);
            font-weight: 700;
        }

        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: #000; }
        ::-webkit-scrollbar-thumb { background: var(--neon-pink); }
    </style>
</head>
