/* 控制面板 */
.control-panel {
    height: 60px;
    background: rgba(0,0,0,0.3);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 15px;
    padding: 0 15px;
    border-top: 1px solid rgba(255,255,255,0.1);
}

.btn-large {
    padding: 10px 20px;
    font-size: 0.9rem;
}

/* 专业模式面板 */
.pro-mode-panel {
    position: fixed;
    bottom: 70px;
    left: 0;
    right: 0;
    background: linear-gradient(180deg, rgba(26,26,46,0.98), rgba(15,52,96,0.98));
    border-top: 2px solid var(--neon-cyan, #00ffff);
    padding: 15px 20px;
    z-index: 100;
    display: none;
    flex-direction: column;
    gap: 15px;
    max-height: 200px;
    overflow-y: auto;
}

.pro-mode-panel.active {
    display: flex;
}

.pro-mode-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--neon-cyan, #00ffff);
    font-size: 0.9rem;
    font-weight: bold;
}

.bpm-display {
    background: rgba(0,255,255,0.1);
    padding: 5px 15px;
    border-radius: 20px;
    border: 1px solid var(--neon-cyan, #00ffff);
}

.chord-grid {
    display: flex;
    justify-content: center;
    gap: 10px;
    flex-wrap: wrap;
}

.chord-btn {
    width: 50px;
    height: 50px;
    border: 2px solid rgba(255,255,255,0.2);
    background: rgba(255,255,255,0.05);
    border-radius: 10px;
    color: #fff;
    font-size: 0.9rem;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.2s;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 2px;
}

.chord-btn:hover {
    border-color: var(--neon-gold, #f5af19);
    background: rgba(245,175,25,0.1);
}

.chord-btn.active {
    border-color: var(--neon-cyan, #00ffff);
    background: rgba(0,255,255,0.2);
    box-shadow: 0 0 15px rgba(0,255,255,0.3);
}

.chord-btn .chord-type {
    font-size: 0.65rem;
    color: rgba(255,255,255,0.6);
    font-weight: normal;
}

.chord-btn.playing {
    animation: chordPulse 0.3s ease-out;
}

@keyframes chordPulse {
    0% { transform: scale(1); }
    50% { transform: scale(1.1); background: rgba(0,255,255,0.4); }
    100% { transform: scale(1); }
}

.mode-toggle {
    background: linear-gradient(135deg, #9b59b6, #8e44ad);
    color: #fff;
}

.mode-toggle.active {
    background: linear-gradient(135deg, #00d2d3, #01a3a4);
}

