// ==================== 工具函数 ====================
function showToast(message) {
    const toast = document.getElementById('toast');
    toast.textContent = message;
    toast.classList.add('show');
    setTimeout(() => toast.classList.remove('show'), 2000);
}

// ==================== 专业模式功能 ====================
function initProMode() {
    const chordGrid = document.getElementById('chordGrid');
    const degrees = ['1', '2', '3', '4', '5', '6', 'b7'];

    degrees.forEach(degree => {
        const chords = chordLibrary[degree];
        // 为每个级数选择一个默认和弦（优先选择包含sus或add的丰富和弦）
        const defaultChordIndex = chords.findIndex(c => c.type.includes('sus') || c.type.includes('add')) || 0;
        const chord = chords[defaultChordIndex];

        const btn = document.createElement('button');
        btn.className = 'chord-btn';
        btn.dataset.degree = degree;
        btn.dataset.chordIndex = defaultChordIndex;
        btn.innerHTML = `
            <span>${degree}</span>
            <span class="chord-type">${chord.name}</span>
        `;

        // 长按切换和弦类型
        let longPressTimer;
        btn.addEventListener('mousedown', () => {
            longPressTimer = setTimeout(() => {
                cycleChordType(btn, degree);
            }, 500);
        });
        btn.addEventListener('mouseup', () => clearTimeout(longPressTimer));
        btn.addEventListener('mouseleave', () => clearTimeout(longPressTimer));

        // 触摸设备支持
        btn.addEventListener('touchstart', (e) => {
            e.preventDefault();
            longPressTimer = setTimeout(() => {
                cycleChordType(btn, degree);
            }, 500);
        });
        btn.addEventListener('touchend', () => clearTimeout(longPressTimer));

        // 点击触发琶音器
        btn.addEventListener('click', () => {
            if (!isProMode) return;
            triggerChordArpeggio(btn, degree, parseInt(btn.dataset.chordIndex));
        });

        chordGrid.appendChild(btn);
    });
}

function cycleChordType(btn, degree) {
    const chords = chordLibrary[degree];
    let currentIndex = parseInt(btn.dataset.chordIndex);
    let nextIndex = (currentIndex + 1) % chords.length;

    // 切换到下一个和弦类型
    btn.dataset.chordIndex = nextIndex;
    const chord = chords[nextIndex];
    btn.innerHTML = `
        <span>${degree}</span>
        <span class="chord-type">${chord.name}</span>
    `;

    showToast(`${degree}级: ${chord.name} ${chord.type}`);
}

function triggerChordArpeggio(btn, degree, chordIndex) {
    initAudio();

    // 触发限制：如果正在播放，先停止当前琶音
    if (isArpeggiatorPlaying) {
        stopArpeggio();
    }

    const chords = chordLibrary[degree];
    const chord = chords[chordIndex];

    // 视觉反馈
    document.querySelectorAll('.chord-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    activeChordBtn = btn;

    // 显示当前和弦
    showToast(`${chord.name} ${chord.type}`);

    // 播放琶音（和弦分解）
    isArpeggiatorPlaying = true;
    currentChord = chord;

    // 琶音模式：上行分解
    playArpeggioPattern(chord.notes, 'up');
}

function playArpeggioPattern(notes, pattern = 'up') {
    const noteDuration = SIXTEENTH_NOTE_MS; // 16分音符

    if (pattern === 'up') {
        // 上行琶音
        notes.forEach((freq, index) => {
            arpeggiatorTimeout = setTimeout(() => {
                if (isArpeggiatorPlaying) {
                    playBellSound(freq, 1.5); // 稍短的音长

                    // 最后一个音播放完后重置状态
                    if (index === notes.length - 1) {
                        setTimeout(() => {
                            isArpeggiatorPlaying = false;
                            if (activeChordBtn) {
                                activeChordBtn.classList.remove('active');
                            }
                        }, noteDuration);
                    }
                }
            }, index * noteDuration);
        });
    }
}

function stopArpeggio() {
    isArpeggiatorPlaying = false;
    if (arpeggiatorTimeout) {
        clearTimeout(arpeggiatorTimeout);
    }
    if (activeChordBtn) {
        activeChordBtn.classList.remove('active');
        activeChordBtn = null;
    }
}

function toggleProMode() {
    isProMode = !isProMode;
    const panel = document.getElementById('proModePanel');
    const btn = document.getElementById('btnProMode');

    if (isProMode) {
        panel.classList.add('active');
        btn.classList.add('active');
        btn.innerHTML = '🎹 退出专业';
        showToast('专业模式开启 - BPM 80');
    } else {
        panel.classList.remove('active');
        btn.classList.remove('active');
        btn.innerHTML = '🎹 专业模式';
        stopArpeggio();
    }
}

