function playArpeggioPattern(notes, pattern = 'up') {
    const noteDuration = SIXTEENTH_NOTE_MS; // 16分音符

    // 清理之前的定时器
    arpeggiatorTimeouts.forEach(id => clearTimeout(id));
    arpeggiatorTimeouts = [];

    if (pattern === 'up') {
        // 上行琶音
        notes.forEach((freq, index) => {
            const timeoutId = setTimeout(() => {
                if (isArpeggiatorPlaying) {
                    playBellSound(freq, 1.5); // 稍短的音长

                    // 最后一个音播放完后重置状态
                    if (index === notes.length - 1) {
                        const resetId = setTimeout(() => {
                            isArpeggiatorPlaying = false;
                            if (activeChordBtn) {
                                activeChordBtn.classList.remove('active');
                            }
                        }, noteDuration);
                        arpeggiatorTimeouts.push(resetId);
                    }
                }
            }, index * noteDuration);
            arpeggiatorTimeouts.push(timeoutId);
        });
    }
}

