document.addEventListener('DOMContentLoaded', () => {
    initBells();
    updateRecordingList();
    checkSharedRecording();
    initProMode(); // 初始化专业模式

    // 专业模式切换按钮
    document.getElementById('btnProMode').addEventListener('click', toggleProMode);

    // 点击空白关闭弹窗
    document.querySelectorAll('.modal').forEach(modal => {
        modal.addEventListener('click', (e) => {
            if (e.target === modal) {
                modal.classList.remove('show');
            }
        });
    });

    // 首次用户交互时初始化音频并预加载所有声音
    const firstInteractionHandler = () => {
        initAudio();
        // 延迟一点时间让音频上下文准备好
        setTimeout(() => {
            preloadAllSounds();
            showToast('🎵 音频缓存完成 - 点击即可播放');
        }, 100);
        document.removeEventListener('click', firstInteractionHandler);
        document.removeEventListener('touchstart', firstInteractionHandler);
    };
    document.addEventListener('click', firstInteractionHandler);
