// ==================== 专业模式功能 ====================
function initProMode() {
    const chordGrid = document.getElementById('chordGrid');
    const degrees = ['1', '2', '3', '4', '5', '6', 'b7'];

    degrees.forEach(degree => {
        const chordData = chordLibrary[degree];
        const chords = chordData.chords;
        // 为每个级数选择一个默认和弦（优先选择包含sus或add的丰富和弦）
        const defaultChordIndex = chords.findIndex(c => c.type.includes('sus') || c.type.includes('add')) || 0;
        const chord = chords[defaultChordIndex];

        const btn = document.createElement('button');
        btn.className = 'chord-btn';
        btn.dataset.degree = degree;
        btn.dataset.chordIndex = defaultChordIndex;
        btn.innerHTML = `
            <span>${degree}</span>
            <span class="chord-type">${chord.name}</span>
        `;

        // 长按切换和弦类型
        let longPressTimer;
        btn.addEventListener('mousedown', () => {
            longPressTimer = setTimeout(() => {
                cycleChordType(btn, degree);
            }, 500);
        });
        btn.addEventListener('mouseup', () => clearTimeout(longPressTimer));
        btn.addEventListener('mouseleave', () => clearTimeout(longPressTimer));

        // 触摸设备支持
        btn.addEventListener('touchstart', (e) => {
            e.preventDefault();
            longPressTimer = setTimeout(() => {
                cycleChordType(btn, degree);
            }, 500);
        });
        btn.addEventListener('touchend', () => clearTimeout(longPressTimer));

        // 点击触发琶音器
        btn.addEventListener('click', () => {
            if (!isProMode) return;
            triggerChordArpeggio(btn, degree, parseInt(btn.dataset.chordIndex));
        });

        chordGrid.appendChild(btn);
    });
}

function cycleChordType(btn, degree) {
    const chordData = chordLibrary[degree];
    const chords = chordData.chords;
    let currentIndex = parseInt(btn.dataset.chordIndex);
    let nextIndex = (currentIndex + 1) % chords.length;

    // 切换到下一个和弦类型
    btn.dataset.chordIndex = nextIndex;
    const chord = chords[nextIndex];
    btn.innerHTML = `
        <span>${degree}</span>
        <span class="chord-type">${chord.name}</span>
    `;

    showToast(`${degree}级: ${chord.name} ${chord.type}`);
}

// 根据pattern生成音符频率数组
function generateChordNotes(rootFreq, pattern) {
    const notes = [];
    for (const interval of pattern) {
        const ratio = INTERVAL_RATIOS[interval];
        notes.push(rootFreq * ratio);
    }
    return notes;
}

function triggerChordArpeggio(btn, degree, chordIndex) {
    initAudio();

    // 触发限制：如果正在播放，先停止当前琶音
    if (isArpeggiatorPlaying) {
        stopArpeggio();
    }

    const chordData = chordLibrary[degree];
    const chord = chordData.chords[chordIndex];
    const rootFreq = chordData.rootFreq;

    // 生成音符频率
    const notes = generateChordNotes(rootFreq, chord.pattern);

    // 视觉反馈
    document.querySelectorAll('.chord-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    activeChordBtn = btn;

    // 显示当前和弦
    showToast(`${chord.name} ${chord.type}`);

    // 播放琶音（和弦分解）
    isArpeggiatorPlaying = true;
    currentChord = chord;

    // 琶音模式：4/4拍 15135结构
    playArpeggioPattern(notes);
}

function playArpeggioPattern(notes) {
    const now = audioContext.currentTime;

    // 清理之前的定时器
    arpeggiatorTimeouts.forEach(id => clearTimeout(id));
    arpeggiatorTimeouts = [];

    // 5个音的 15135 结构，4/4拍
    // 0ms: 音1, 600ms: 音5, 1200ms: 音1, 1800ms: 音3, 2400ms: 音5(延长)
    const noteCount = notes.length;
    const regularNoteDuration = EIGHTH_NOTE_MS / 1000; // 8分音符秒数
    const finalNoteDuration = (BEAT_MS * FINAL_NOTE_BEATS) / 1000; // 最后音延长两拍

    // 前4个音按时序播放（每个8分音符）
    for (let i = 0; i < noteCount - 1; i++) {
        const playTime = now + (i * regularNoteDuration);
        const freq = notes[i];

        // 确保音频缓冲已生成
        if (!audioBufferCache[freq]) {
            audioBufferCache[freq] = generateBellBuffer(freq);
        }

        const source = audioContext.createBufferSource();
        source.buffer = audioBufferCache[freq];
        source.connect(masterGain);
        source.start(playTime);
    }

    // 最后一个音：延长两拍
    const lastIndex = noteCount - 1;
    const lastPlayTime = now + (lastIndex * regularNoteDuration);
    const lastFreq = notes[lastIndex];

    if (!audioBufferCache[lastFreq]) {
        audioBufferCache[lastFreq] = generateBellBuffer(lastFreq);
    }

    const lastSource = audioContext.createBufferSource();
    lastSource.buffer = audioBufferCache[lastFreq];
    lastSource.connect(masterGain);
    lastSource.start(lastPlayTime);

    // 视觉反馈和状态重置定时器
    const visualTimeouts = [
        setTimeout(() => {}, 0),
        setTimeout(() => {}, EIGHTH_NOTE_MS),
        setTimeout(() => {}, EIGHTH_NOTE_MS * 2),
        setTimeout(() => {}, EIGHTH_NOTE_MS * 3),
        setTimeout(() => {}, EIGHTH_NOTE_MS * 4)
    ];

    // 4拍后重置状态（最后一个音持续两拍，所以总时长是 4拍）
    const resetTimeout = setTimeout(() => {
        isArpeggiatorPlaying = false;
        if (activeChordBtn) {
            activeChordBtn.classList.remove('active');
        }
    }, BEAT_MS * 4); // 4拍 = 4800ms @ BPM 50

    arpeggiatorTimeouts = [...visualTimeouts, resetTimeout];
}

function stopArpeggio() {
    isArpeggiatorPlaying = false;
    // 清理所有定时器
    arpeggiatorTimeouts.forEach(id => clearTimeout(id));
    arpeggiatorTimeouts = [];
    if (activeChordBtn) {
        activeChordBtn.classList.remove('active');
        activeChordBtn = null;
    }
}

function toggleProMode() {
    isProMode = !isProMode;
    const panel = document.getElementById('proModePanel');
    const btn = document.getElementById('btnProMode');

    if (isProMode) {
        panel.classList.add('active');
        btn.classList.add('active');
        btn.innerHTML = '🎹 退出专业';
        showToast('专业模式开启 - BPM 50');
    } else {
        panel.classList.remove('active');
        btn.classList.remove('active');
        btn.innerHTML = '🎹 专业模式';
        stopArpeggio();
    }
}

