        // 音程倍数 (十二平均律)
        const INTERVAL_RATIOS = {
            1: 1,           // 根音
            2: 1.122462,    // 大二度
            3: 1.189207,    // 小三度 (降3度)
            4: 1.334840,    // 纯四度
            5: 1.498307,    // 纯五度
