                    { name: 'Fsus2', type: 'sus2', pattern: [1, 5, 'octave', 2, 5] },
                    { name: 'Fadd9', type: 'add9', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Fmaj7', type: 'maj7', pattern: [1, 5, 'octave', 3, 7] },
