            },
            '5': { // G 和弦 - 根音G1 (49.00Hz)
                rootFreq: 49.00,
                chords: [
                    { name: 'G', type: '大三', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Gsus4', type: 'sus4', pattern: [1, 5, 'octave', 4, 5] },
                    { name: 'Gadd9', type: 'add9', pattern: [1, 5, 'octave', 3, 5] },
