    <!-- 分享弹窗 -->
    <div class="modal" id="shareModal">
        <div class="modal-content">
            <div class="modal-header">
                <h3>📤 分享演奏</h3>
                <button class="modal-close" onclick="closeShareModal()">×</button>
            </div>
            <div class="modal-body">
                <div class="share-options">
                    <button class="share-btn" onclick="shareToWeChat()">
                        💬 生成分享卡片
                    </button>
                    <button class="share-btn" onclick="copyLink()">
                        🔗 复制分享链接
                    </button>
                    <button class="share-btn" onclick="downloadRecording()">
                        💾 导出演奏数据
                    </button>
                </div>
                <div id="shareCardContainer"></div>
            </div>
        </div>
    </div>

    <!-- 提示信息 -->
    <div class="toast" id="toast"></div>

    <script>
        // ==================== 专业模式配置 ====================
        const BPM = 50; // BPM 50
        const BEAT_MS = 60000 / BPM; // 每拍时长 (1200ms @ BPM 50)
        const EIGHTH_NOTE_MS = BEAT_MS / 2; // 8分音符 (600ms)
        const FINAL_NOTE_BEATS = 2; // 最后一个音停两拍

        // 音程倍数 (十二平均律)
        const INTERVAL_RATIOS = {
            1: 1,           // 根音
            2: 1.122462,    // 大二度
            3: 1.189207,    // 小三度 (降3度)
            4: 1.334840,    // 纯四度
            5: 1.498307,    // 纯五度
            6: 1.681793,    // 大六度
            7: 1.887748,    // 大七度
            b3: 1.189207,   // 小三度
            b7: 1.781797,   // 小七度
            octave: 2       // 八度
        };

        // 和弦库 - 4/4拍 15135琶音结构
        // 1级(C)和2级(D)根音在C2音区 (65.41Hz)
        // 其他级数根音在C1音区 (32.70Hz)
        const chordLibrary = {
            '1': { // C 和弦 - 根音C2 (65.41Hz)
                rootFreq: 65.41,
                chords: [
                    { name: 'C', type: '大三', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Csus2', type: 'sus2', pattern: [1, 5, 'octave', 2, 5] },
                    { name: 'Csus4', type: 'sus4', pattern: [1, 5, 'octave', 4, 5] },
                    { name: 'Cadd9', type: 'add9', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'C6', type: '6', pattern: [1, 5, 'octave', 3, 6] }
                ]
            },
            '2': { // Dm 和弦 - 根音D2 (73.42Hz)
                rootFreq: 73.42,
                chords: [
                    { name: 'Dm', type: '小三', pattern: [1, 5, 'octave', 'b3', 5] },
                    { name: 'Dsus2', type: 'sus2', pattern: [1, 5, 'octave', 2, 5] },
                    { name: 'Dsus4', type: 'sus4', pattern: [1, 5, 'octave', 4, 5] },
                    { name: 'Dm7', type: 'm7', pattern: [1, 5, 'octave', 'b3', 'b7'] },
                    { name: 'D7sus4', type: '7sus4', pattern: [1, 5, 'octave', 4, 'b7'] }
                ]
            },
            '3': { // Em 和弦 - 根音E1 (41.20Hz = C1 * 大三度)
                rootFreq: 41.20,
                chords: [
                    { name: 'Em', type: '小三', pattern: [1, 5, 'octave', 'b3', 5] },
                    { name: 'Esus4', type: 'sus4', pattern: [1, 5, 'octave', 4, 5] },
                    { name: 'E7', type: '属7', pattern: [1, 5, 'octave', 'b3', 'b7'] },
                    { name: 'Emadd9', type: 'madd9', pattern: [1, 5, 'octave', 'b3', 5] },
                    { name: 'Em7', type: 'm7', pattern: [1, 5, 'octave', 'b3', 'b7'] }
                ]
            },
            '4': { // F 和弦 - 根音F1 (43.65Hz)
                rootFreq: 43.65,
                chords: [
                    { name: 'F', type: '大三', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Fsus2', type: 'sus2', pattern: [1, 5, 'octave', 2, 5] },
                    { name: 'Fadd9', type: 'add9', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Fmaj7', type: 'maj7', pattern: [1, 5, 'octave', 3, 7] },
                    { name: 'F6', type: '6', pattern: [1, 5, 'octave', 3, 6] }
                ]
            },
            '5': { // G 和弦 - 根音G1 (49.00Hz)
                rootFreq: 49.00,
                chords: [
                    { name: 'G', type: '大三', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Gsus4', type: 'sus4', pattern: [1, 5, 'octave', 4, 5] },
                    { name: 'Gadd9', type: 'add9', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'G7', type: '属7', pattern: [1, 5, 'octave', 3, 'b7'] },
                    { name: 'G6', type: '6', pattern: [1, 5, 'octave', 3, 6] }
                ]
            },
            '6': { // Am 和弦 - 根音A1 (55.00Hz)
                rootFreq: 55.00,
                chords: [
                    { name: 'Am', type: '小三', pattern: [1, 5, 'octave', 'b3', 5] },
                    { name: 'Asus2', type: 'sus2', pattern: [1, 5, 'octave', 2, 5] },
                    { name: 'Asus4', type: 'sus4', pattern: [1, 5, 'octave', 4, 5] },
                    { name: 'Am7', type: 'm7', pattern: [1, 5, 'octave', 'b3', 'b7'] },
                    { name: 'Amadd9', type: 'madd9', pattern: [1, 5, 'octave', 'b3', 5] }
                ]
            },
            'b7': { // Bb 和弦 - 根音Bb1 (58.27Hz)
                rootFreq: 58.27,
                chords: [
                    { name: 'Bb', type: '大三', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Bbsus4', type: 'sus4', pattern: [1, 5, 'octave', 4, 5] },
                    { name: 'Bbadd9', type: 'add9', pattern: [1, 5, 'octave', 3, 5] },
                    { name: 'Bb7', type: '属7', pattern: [1, 5, 'octave', 3, 'b7'] },
                    { name: 'Bb6', type: '6', pattern: [1, 5, 'octave', 3, 6] }
                ]
            }
        };

        // 专业模式状态
        let isProMode = false;
        let isArpeggiatorPlaying = false;
        let currentChord = null;
        let arpeggiatorTimeouts = [];
        let activeChordBtn = null;

        // ==================== 音频上下文 ====================
        let audioContext = null;
        let masterGain = null;

        function initAudio() {
            if (!audioContext) {
                audioContext = new (window.AudioContext || window.webkitAudioContext)();
                masterGain = audioContext.createGain();
                masterGain.gain.value = 0.8;
                masterGain.connect(audioContext.destination);
            }
            if (audioContext.state === 'suspended') {
                audioContext.resume();
            }
        }

        // ==================== 编钟音阶配置 ====================
        // 基于曾侯乙编钟的音阶结构 - 一钟双音特性
        // 每口钟有正鼓音（敲击正鼓部）和侧鼓音（敲击侧鼓部），通常相隔三度
        const bellConfig = {
            row1: [  // 上层 - 小编钟（高音区 C5-A5）
                { note: 'C5',  sideNote: 'E5',  freq: 523.25,  sideFreq: 659.25,  label: 'C' },
                { note: 'D5',  sideNote: 'F5',  freq: 587.33,  sideFreq: 698.46,  label: 'D' },
                { note: 'E5',  sideNote: 'G5',  freq: 659.25,  sideFreq: 783.99,  label: 'E' },
                { note: 'G5',  sideNote: 'B5',  freq: 783.99,  sideFreq: 987.77,  label: 'G' },
                { note: 'A5',  sideNote: 'C6',  freq: 880.00,  sideFreq: 1046.50, label: 'A' }
            ],
            row2: [  // 中层 - 中编钟（中音区 C4-A4）
                { note: 'C4',  sideNote: 'E4',  freq: 261.63,  sideFreq: 329.63,  label: 'C' },
                { note: 'D4',  sideNote: 'F4',  freq: 293.66,  sideFreq: 349.23,  label: 'D' },
                { note: 'E4',  sideNote: 'G4',  freq: 329.63,  sideFreq: 392.00,  label: 'E' },
                { note: 'G4',  sideNote: 'B4',  freq: 392.00,  sideFreq: 493.88,  label: 'G' },
                { note: 'A4',  sideNote: 'C5',  freq: 440.00,  sideFreq: 523.25,  label: 'A' }
            ],
            row3: [  // 下层 - 大编钟（低音区 C3-A3）
                { note: 'C3',  sideNote: 'E3',  freq: 130.81,  sideFreq: 164.81,  label: 'C' },
                { note: 'D3',  sideNote: 'F3',  freq: 146.83,  sideFreq: 174.61,  label: 'D' },
                { note: 'E3',  sideNote: 'G3',  freq: 164.81,  sideFreq: 196.00,  label: 'E' },
                { note: 'G3',  sideNote: 'B3',  freq: 196.00,  sideFreq: 246.94,  label: 'G' },
                { note: 'A3',  sideNote: 'C4',  freq: 220.00,  sideFreq: 261.63,  label: 'A' }
            ]
        };

        // ==================== 编钟音色合成 ====================
        // 音频缓存 - 预生成所有音色的 AudioBuffer
        const audioBufferCache = {};
        const BUFFER_DURATION = 3.0; // 3秒音频缓冲
        const SAMPLE_RATE = 44100;

        // 生成编钟音色的 AudioBuffer
        function generateBellBuffer(freq) {
            const length = BUFFER_DURATION * SAMPLE_RATE;
            const buffer = audioContext.createBuffer(1, length, SAMPLE_RATE);
            const data = buffer.getChannelData(0);

            // 基频 + 二次谐波 + 三次谐波合成
            const fundamental = freq;
            const harmonic2 = freq * 2;
            const harmonic3 = freq * 3;

            for (let i = 0; i < length; i++) {
                const t = i / SAMPLE_RATE;

                // 基频 (正弦波) - 音量 0.6，3秒衰减
                const env1 = Math.exp(-t / 0.5); // 衰减时间常数
                const wave1 = Math.sin(2 * Math.PI * fundamental * t) * 0.6 * env1;

                // 二次谐波 (正弦波) - 音量 0.3，2.4秒衰减
                const env2 = Math.exp(-t / 0.4);
                const wave2 = Math.sin(2 * Math.PI * harmonic2 * t) * 0.3 * env2;

                // 三次谐波 (三角波近似) - 音量 0.15，1.5秒衰减
                const env3 = Math.exp(-t / 0.25);
                // 三角波：用锯齿波的奇次谐波近似
                let triWave = 0;
                for (let h = 1; h <= 5; h += 2) {
                    triWave += Math.sin(2 * Math.PI * harmonic3 * h * t) / (h * h);
                }
                triWave *= 0.15 * env3;

                // 快速起音 (Attack 20ms)
                let attack = 1;
                if (t < 0.02) {
                    attack = t / 0.02;
                }

                data[i] = (wave1 + wave2 + triWave) * attack;
            }

            return buffer;
        }

        // 预生成所有需要的频率的 AudioBuffer
        function preloadAllSounds() {
            const allFreqs = [];

            // 收集所有编钟频率
            Object.values(bellConfig).forEach(row => {
                row.forEach(bell => {
                    allFreqs.push(bell.freq);
                    allFreqs.push(bell.sideFreq);
                });
            });

            // 收集和弦库中的所有频率
            Object.values(chordLibrary).forEach(chords => {
                chords.forEach(chord => {
                    chord.notes.forEach(freq => {
                        if (!allFreqs.includes(freq)) {
                            allFreqs.push(freq);
                        }
                    });
                });
            });

            // 预生成所有 AudioBuffer
            allFreqs.forEach(freq => {
                if (!audioBufferCache[freq]) {
                    audioBufferCache[freq] = generateBellBuffer(freq);
                }
            });

            console.log(`预加载完成: ${Object.keys(audioBufferCache).length} 个音色`);
        }

        // 播放缓存的音频（低延迟）
        function playBellSound(freq, duration = 3) {
            initAudio();

            // 如果缓存中不存在，实时生成
            if (!audioBufferCache[freq]) {
                audioBufferCache[freq] = generateBellBuffer(freq);
            }

            const source = audioContext.createBufferSource();
            source.buffer = audioBufferCache[freq];
            source.connect(masterGain);
            source.start();
        }

        // ==================== 初始化编钟界面 ====================
        function initBells() {
            // 上层
            const row1 = document.getElementById('row1');
            bellConfig.row1.forEach((bell, index) => {
                row1.appendChild(createBellElement(bell, 'small', index));
            });

            // 中层
            const row2 = document.getElementById('row2');
            bellConfig.row2.forEach((bell, index) => {
                row2.appendChild(createBellElement(bell, 'medium', index));
            });

            // 下层
            const row3 = document.getElementById('row3');
            bellConfig.row3.forEach((bell, index) => {
                row3.appendChild(createBellElement(bell, 'large', index));
            });
        }

        function createBellElement(config, size, index) {
            const bell = document.createElement('div');
            bell.className = `bell bell-${size}`;
            bell.dataset.note = config.note;
            bell.dataset.freq = config.freq;
            bell.dataset.sideNote = config.sideNote;
            bell.dataset.sideFreq = config.sideFreq;

            bell.innerHTML = `
                <div class="bell-body">
                    <div class="bell-zheng">正</div>
                    <div class="bell-ce">侧</div>
                    <span class="bell-label">${config.label}</span>
                    <span class="bell-notes">${config.note}/${config.sideNote}</span>
                </div>
                <span class="mallet-hit">🔨</span>
            `;

            // 点击事件 - 根据点击位置判断正敲或侧敲
            bell.addEventListener('click', (e) => {
                const rect = bell.getBoundingClientRect();
                const x = e.clientX - rect.left;
                const isSide = x < rect.width / 2; // 左半边为侧敲，右半边为正敲
                hitBell(bell, config, isSide);
            });

            bell.addEventListener('touchstart', (e) => {
                e.preventDefault();
                const rect = bell.getBoundingClientRect();
                const touch = e.touches[0];
                const x = touch.clientX - rect.left;
                const isSide = x < rect.width / 2;
                hitBell(bell, config, isSide);
            });

            return bell;
        }

        function hitBell(element, config, isSide = false) {
            initAudio();

            // 根据敲击位置选择音高
            const freq = isSide ? config.sideFreq : config.freq;
            const note = isSide ? config.sideNote : config.note;
            const hitType = isSide ? '侧敲' : '正敲';

            // 播放声音
            playBellSound(freq);

            // 视觉反馈
            element.classList.add('bell-swing');
            setTimeout(() => element.classList.remove('bell-swing'), 300);

            // 击槌动画 - 根据敲击位置显示
            const mallet = element.querySelector('.mallet-hit');
            mallet.textContent = isSide ? '🔨·' : '·🔨';
            mallet.classList.add('show');
            setTimeout(() => mallet.classList.remove('show'), 200);

            // 显示提示
            showToast(`${config.label} · ${hitType} · ${note}`);

            // 录制
            if (isRecording) {
                recordNote(note, freq, isSide);
            }
        }

        // ==================== 录制功能 ====================
        let isRecording = false;
        let recordingStartTime = 0;
        let currentRecording = [];
        let recordings = JSON.parse(localStorage.getItem('bianzhong_recordings') || '[]');
        let recordTimer = null;

        document.getElementById('btnRecord').addEventListener('click', toggleRecording);

        function toggleRecording() {
            if (isRecording) {
                stopRecording();
            } else {
                startRecording();
            }
        }

        function startRecording() {
            initAudio();
            isRecording = true;
            recordingStartTime = Date.now();
            currentRecording = [];

            const btn = document.getElementById('btnRecord');
            btn.classList.add('recording');
            btn.innerHTML = '⏹️ 停止';

            document.getElementById('recordingIndicator').classList.add('active');
            document.getElementById('statusText').textContent = '正在录制...';
            document.getElementById('recordTime').style.display = 'block';

            // 开始计时
            recordTimer = setInterval(updateRecordTime, 1000);

            showToast('开始录制，敲击编钟吧！');
        }

        function stopRecording() {
            isRecording = false;
            clearInterval(recordTimer);

            const btn = document.getElementById('btnRecord');
            btn.classList.remove('recording');
            btn.innerHTML = '🔴 录制';

            document.getElementById('recordingIndicator').classList.remove('active');
            document.getElementById('statusText').textContent = '录制完成';
            document.getElementById('recordTime').style.display = 'none';
            document.getElementById('timeDisplay').textContent = '00:00';

            // 保存录制
            if (currentRecording.length > 0) {
                const recording = {
                    id: Date.now(),
                    name: `演奏 ${recordings.length + 1}`,
                    date: new Date().toLocaleString(),
                    duration: ((Date.now() - recordingStartTime) / 1000).toFixed(1),
                    notes: currentRecording
                };
                recordings.push(recording);
                localStorage.setItem('bianzhong_recordings', JSON.stringify(recordings));

                showToast('录制已保存！');
                updateRecordingList();
            }
        }

        function updateRecordTime() {
            const elapsed = Math.floor((Date.now() - recordingStartTime) / 1000);
            const minutes = Math.floor(elapsed / 60).toString().padStart(2, '0');
            const seconds = (elapsed % 60).toString().padStart(2, '0');
            document.getElementById('timeDisplay').textContent = `${minutes}:${seconds}`;
        }

        function recordNote(note, freq, isSide = false) {
            currentRecording.push({
                note: note,
                freq: freq,
                isSide: isSide,
                time: Date.now() - recordingStartTime
            });
        }

        // ==================== 回放功能 ====================
        let isPlaying = false;

        document.getElementById('btnPlayback').addEventListener('click', () => {
            if (recordings.length > 0) {
                playRecording(recordings[recordings.length - 1]);
            }
        });

        function playRecording(recording) {
            if (isPlaying || !recording.notes.length) return;

            isPlaying = true;
            showToast('开始回放...');

            recording.notes.forEach((noteData) => {
                setTimeout(() => {
                    playBellSound(noteData.freq);
                }, noteData.time);
            });

            setTimeout(() => {
                isPlaying = false;
            }, recording.notes[recording.notes.length - 1].time + 1000);
        }

        // ==================== 录制列表 ====================
        document.getElementById('btnRecordings').addEventListener('click', () => {
            updateRecordingList();
            document.getElementById('recordingsModal').classList.add('show');
        });

        function updateRecordingList() {
            const list = document.getElementById('recordingList');

            if (recordings.length === 0) {
                list.innerHTML = `
                    <div class="empty-state">
                        <div class="icon">🎵</div>
                        <p>还没有录制任何演奏</p>
                        <p style="font-size: 0.85rem; margin-top: 5px;">点击录制按钮开始创作吧！</p>
                    </div>
                `;
                document.getElementById('btnPlayback').disabled = true;
            } else {
                list.innerHTML = recordings.map(rec => {
                    const sideCount = rec.notes.filter(n => n.isSide).length;
                    const zhengCount = rec.notes.length - sideCount;
                    return `
                    <li class="recording-item">
                        <div class="recording-info">
                            <div class="recording-name">${rec.name}</div>
                            <div class="recording-time">${rec.date} · ${rec.duration}秒 · ${rec.notes.length}音(正${zhengCount}/侧${sideCount})</div>
                        </div>
                        <div class="recording-actions">
                            <button class="btn-icon play" onclick="playRecordingById(${rec.id})">▶</button>
                            <button class="btn-icon" onclick="shareRecording(${rec.id})" style="background: #3b82f6;">📤</button>
                            <button class="btn-icon delete" onclick="deleteRecording(${rec.id})">🗑</button>
                        </div>
                    </li>
                `}).join('');
                document.getElementById('btnPlayback').disabled = false;
            }
        }

        function playRecordingById(id) {
            const recording = recordings.find(r => r.id === id);
            if (recording) {
                playRecording(recording);
                closeModal();
            }
        }

        function deleteRecording(id) {
            if (confirm('确定要删除这个演奏吗？')) {
                recordings = recordings.filter(r => r.id !== id);
                localStorage.setItem('bianzhong_recordings', JSON.stringify(recordings));
                updateRecordingList();
                showToast('已删除');
            }
        }

        function closeModal() {
            document.getElementById('recordingsModal').classList.remove('show');
        }

        // ==================== 分享功能 ====================
        let shareTargetId = null;

        function shareRecording(id) {
            shareTargetId = id;
            document.getElementById('shareModal').classList.add('show');
        }

        function closeShareModal() {
            document.getElementById('shareModal').classList.remove('show');
            document.getElementById('shareCardContainer').innerHTML = '';
            shareTargetId = null;
        }

        // 生成分享链接
        function generateShareLink() {
            if (!shareTargetId) return;

            const recording = recordings.find(r => r.id === shareTargetId);
            if (!recording) return;

            // 将录制数据编码为Base64
            const data = JSON.stringify({
                name: recording.name,
                notes: recording.notes,
                duration: recording.duration
            });
            const encoded = btoa(encodeURIComponent(data));

            // 生成链接
            const link = `${window.location.origin}${window.location.pathname}?share=${encoded}`;
            return link;
        }

        function copyLink() {
            const link = generateShareLink();
            if (link) {
                // 复制到剪贴板
                if (navigator.clipboard) {
                    navigator.clipboard.writeText(link).then(() => {
                        showToast('链接已复制到剪贴板！');
                    }).catch(() => {
                        fallbackCopy(link);
                    });
                } else {
                    fallbackCopy(link);
                }
            }
            closeShareModal();
        }

        function fallbackCopy(text) {
            const textarea = document.createElement('textarea');
            textarea.value = text;
            textarea.style.position = 'fixed';
            textarea.style.opacity = '0';
            document.body.appendChild(textarea);
